# --------------------------------------------------------------------------
# Transport (Bucket A: session_and_auth + module-level cache)
# --------------------------------------------------------------------------

_SESSION: Optional[requests.Session] = None
_AUTH: Any = None


def _get_session() -> Tuple[requests.Session, Any]:
    """Lazily create and cache the (Session, auth) pair.

    In PRISM, session_and_auth() returns a requests.Session pre-wired with
    the Kerberos proxy adapter plus an HTTPKerberosAuth. Through the staging
    stub mirror it returns a vanilla Session and None auth.
    """
    global _SESSION, _AUTH
    if _SESSION is None:
        _SESSION, _AUTH = session_and_auth()
    return _SESSION, _AUTH


def _wds_get(method: str) -> Any:
    """GET a WDS REST method that takes no body (getCodeSets,
    getAllCubesListLite, ...). Returns parsed JSON."""
    session, auth = _get_session()
    url = f"{WDS_BASE}/{method}"
    resp = session.get(url, auth=auth, timeout=DEFAULT_TIMEOUT)
    if resp.status_code != 200:
        raise StatCanError(f"WDS {method} -> HTTP {resp.status_code}")
    return resp.json()


def _wds_post(method: str, body: Any) -> Any:
    """POST a WDS REST method with a JSON body (getCubeMetadata,
    getDataFromVectorsAndLatestNPeriods, getSeriesInfoFromVector, ...)."""
    session, auth = _get_session()
    url = f"{WDS_BASE}/{method}"
    resp = session.post(url, json=body, auth=auth, timeout=DEFAULT_TIMEOUT)
    if resp.status_code != 200:
        raise StatCanError(f"WDS {method} -> HTTP {resp.status_code}")
    return resp.json()


def _sdmx_get(path: str, params: Optional[Dict[str, Any]] = None) -> Any:
    """GET an SDMX REST path and parse the SDMX-JSON body. ``path`` is the
    portion after SDMX_BASE (e.g. ``data/DF_18100004/2.2`` or
    ``vector/v41690973``)."""
    session, auth = _get_session()
    url = f"{SDMX_BASE}/{path}"
    headers = {"Accept": SDMX_JSON_ACCEPT}
    resp = session.get(url, params=params or {}, headers=headers,
                       auth=auth, timeout=DEFAULT_TIMEOUT)
    if resp.status_code == 404:
        # SDMX returns 404 when no series match the query (per the guide's
        # status-code table). Surface as an empty result, not an exception:
        # an over-narrow / wildcard-miss key is a normal outcome PRISM
        # iterates on, not a transport failure.
        return None
    if resp.status_code != 200:
        raise StatCanError(f"SDMX {path} -> HTTP {resp.status_code}: "
                           f"{resp.text[:200]}")
    return resp.json()


# --------------------------------------------------------------------------
# SDMX-JSON parser
# --------------------------------------------------------------------------
# StatCan's SDMX-JSON mislabels TIME_PERIOD.id / .name (e.g. 2024-02 is
# returned with id "2025"). The only reliable period field is the ISO
# `start` timestamp. The wrapper derives the period label from `start` plus
# the series frequency (inferred from observation spacing, or the cube /
# vector frequency code), so PRISM never sees the upstream bug.

_FREQ_TO_GRAN = {
    "1": "D", "21": "D", "2": "W", "4": "W", "6": "M", "7": "M", "20": "M",
    "9": "Q", "19": "Q", "11": "S", "12": "A", "13": "A", "14": "A",
    "15": "A", "16": "A", "17": "A", "18": "A",
}


def _parse_start(iso: Optional[str]) -> Optional[Tuple[int, int, int]]:
    """Parse an ISO `start` like '2024-02-01T00:00:00' to (y, m, d)."""
    if not iso:
        return None
    try:
        y, m, d = int(iso[0:4]), int(iso[5:7]), int(iso[8:10])
        return (y, m, d)
    except (ValueError, IndexError):
        return None


def _infer_gran(ymd_list: List[Optional[Tuple[int, int, int]]]) -> Optional[str]:
    """Infer granularity from the spacing between consecutive start dates."""
    import datetime
    dts = [datetime.date(*t) for t in ymd_list if t]
    if len(dts) < 2:
        return None
    dts.sort()
    gaps = sorted((dts[i + 1] - dts[i]).days for i in range(len(dts) - 1))
    g = gaps[len(gaps) // 2]
    if g <= 3:
        return "D"
    if g <= 10:
        return "W"
    if g <= 45:
        return "M"
    if g <= 100:
        return "Q"
    if g <= 200:
        return "S"
    return "A"


def _format_period(ymd: Tuple[int, int, int], gran: str) -> str:
    y, m, d = ymd
    if gran in ("D", "W"):
        return f"{y:04d}-{m:02d}-{d:02d}"
    if gran == "M":
        return f"{y:04d}-{m:02d}"
    if gran == "Q":
        return f"{y:04d}-Q{(m - 1) // 3 + 1}"
    if gran == "S":
        return f"{y:04d}-S{1 if m <= 6 else 2}"
    return f"{y:04d}"


def _parse_sdmx_json(payload: Optional[Dict[str, Any]],
                     freq_hint: Optional[Union[str, int, Dict[str, Any]]] = None
                     ) -> List[Dict[str, Any]]:
    """Parse an SDMX-JSON 1.0 payload into clean series dicts.

    Returns ``list[dict]`` where each dict is::

        {
          "key":          "0.0",                       # positional SDMX key
          "dimensions":   {DIM_ID: {"id", "name"}},    # resolved
          "attributes":   {ATTR_ID: value, ...},       # VECTOR_ID, UOM, ...
          "observations": {"2024-01": 158.3, ...},     # period -> float|None
        }

    ``freq_hint`` resolves single-observation series whose granularity can't
    be inferred from spacing: pass a frequency code (cube-level) or a
    ``{vector_id: frequency_code}`` map (vector-level).

    StatCan places several series-constant attributes (VECTOR_ID, UOM,
    SCALAR_FACTOR, NB_DECIMAL, DGUID) under the observation-attribute block;
    any structure attribute with exactly one value is treated as a
    series-constant and attached directly (the reliable way to surface
    VECTOR_ID etc. without per-observation index gymnastics).
    """
    if not payload:
        return []
    struct = payload.get("structure") or {}
    dims = struct.get("dimensions", {}) or {}
    attrs_struct = struct.get("attributes", {}) or {}
    series_dims = dims.get("series", []) or []
    obs_dims = dims.get("observation", []) or []

    # Observation dimension is TIME_PERIOD; keep the reliable `start` field.
    period_starts: List[Optional[Tuple[int, int, int]]] = []
    if obs_dims:
        period_starts = [_parse_start(v.get("start"))
                         for v in obs_dims[0].get("values", [])]

    series_attr_defs = attrs_struct.get("series", []) or []
    obs_attr_defs = attrs_struct.get("observation", []) or []

    constant_attrs: Dict[str, str] = {}
    for adef in list(series_attr_defs) + list(obs_attr_defs):
        vals = adef.get("values") or []
        if len(vals) == 1:
            constant_attrs[adef["id"]] = vals[0].get("name") or vals[0].get("id")

    datasets = payload.get("dataSets") or []
    if not datasets:
        return []
    raw_series = datasets[0].get("series", {}) or {}

    out: List[Dict[str, Any]] = []
    for skey, sobj in raw_series.items():
        idxs = [int(x) for x in re.split(r"[:.]", skey) if x != ""]
        dim_map: Dict[str, Dict[str, Any]] = {}
        for pos, i in enumerate(idxs):
            if pos >= len(series_dims):
                continue
            d = series_dims[pos]
            vals = d.get("values", [])
            if 0 <= i < len(vals):
                v = vals[i]
                dim_map[d["id"]] = {"id": v.get("id"), "name": v.get("name")}

        attributes: Dict[str, Any] = dict(constant_attrs)
        for pos, idx in enumerate(sobj.get("attributes", []) or []):
            if idx is None or pos >= len(series_attr_defs):
                continue
            adef = series_attr_defs[pos]
            vals = adef.get("values") or []
            if isinstance(idx, int) and 0 <= idx < len(vals):
                attributes[adef["id"]] = vals[idx].get("name") or vals[idx].get("id")

        obs_items = sobj.get("observations", {}) or {}
        starts_used = [period_starts[int(oi)] for oi in obs_items
                       if 0 <= int(oi) < len(period_starts)]
        gran = _infer_gran(starts_used)
        if gran is None:
            fc = freq_hint
            if isinstance(freq_hint, dict):
                fc = freq_hint.get(str(attributes.get("VECTOR_ID")))
            gran = _FREQ_TO_GRAN.get(str(fc), "D")

        observations: Dict[str, Any] = {}
        n_per = len(period_starts)
        for oi, arr in obs_items.items():
            # StatCan keys observations by a GLOBAL running index across all
            # series in the response (series N's obs run N*P .. N*P+P-1).
            # Modulo the distinct-period count recovers the per-series index.
            i = int(oi) % n_per if n_per else 0
            ymd = period_starts[i] if 0 <= i < n_per else None
            period = _format_period(ymd, gran) if ymd else str(oi)
            raw = arr[0] if arr else None
            observations[period] = _coerce_number(raw)

        out.append({
            "key": skey,
            "dimensions": dim_map,
            "attributes": attributes,
            "observations": observations,
        })
    return out


def _coerce_number(raw: Any) -> Any:
    """Coerce a string observation to float; pass through None/blank."""
    if raw is None or raw == "":
        return None
    try:
        return float(raw)
    except (TypeError, ValueError):
        return raw


# --------------------------------------------------------------------------
# Discovery — the embedded ontology (no network)
# --------------------------------------------------------------------------

def _fold(text: str) -> str:
    """Casefold + strip diacritics for accent-insensitive search."""
    if not text:
        return ""
    norm = unicodedata.normalize("NFKD", text)
    return "".join(c for c in norm if not unicodedata.combining(c)).casefold()


def list_subjects(macro_only: bool = False) -> List[Dict[str, str]]:
    """List the top-level StatCan subject domains (the ontology's first
    level). Set macro_only=True for just the 11 macro/financial/economic
    domains.

    Returns ``[{"code", "name", "macro": bool}, ...]`` sorted by code.
    """
    out = []
    for code in sorted(_SUBJECT_TOP):
        is_macro = code in MACRO_SUBJECTS
        if macro_only and not is_macro:
            continue
        out.append({"code": code, "name": _SUBJECT_TOP[code], "macro": is_macro})
    return out


def get_subject(code: str) -> Optional[str]:
    """Resolve a subject code (top-level or sub-subject) to its English
    name."""
    code = str(code)
    return _SUBJECT_TOP.get(code) or _SUBJECTS.get(code)


def cubes_by_subject(subject_code: str, frequency: Optional[Union[int, str]] = None,
                     limit: Optional[int] = None) -> List[Dict[str, Any]]:
    """All active cubes tagged with the given top-level subject code
    (matched on the leading 2 digits of each cube's subjects).

    Args:
        subject_code: e.g. "18" (Prices), "36" (Economic accounts).
        frequency: optional frequency-code filter (int or str), e.g. 6 = Monthly.
        limit: cap the number of cubes returned.
    """
    sc = str(subject_code)[:2]
    freq = str(frequency) if frequency is not None else None
    out = []
    for c in _CUBES:
        if not any(str(s)[:2] == sc for s in (c.get("s") or [])):
            continue
        if freq is not None and str(c.get("f")) != freq:
            continue
        out.append(_cube_view(c))
        if limit and len(out) >= limit:
            break
    return out


def search_cubes(keyword: str, subject: Optional[str] = None,
                 frequency: Optional[Union[int, str]] = None,
                 limit: int = 50, live_archived: bool = False) -> List[Dict[str, Any]]:
    """Search the embedded cube index by title keyword(s) (accent- and
    case-insensitive; all whitespace-separated tokens must match).

    Args:
        keyword: one or more tokens; all must appear in the title.
        subject: optional top-level subject-code filter ("18", "36", ...).
        frequency: optional frequency-code filter.
        limit: max cubes to return.
        live_archived: if True, also query live getAllCubesListLite-equivalent
            coverage is NOT re-fetched (the embedded index already holds all
            active cubes); this flag is reserved and currently a no-op since
            the embedded index is the active universe. Use get_cube_metadata
            for any specific archived PID.
    """
    tokens = [_fold(t) for t in keyword.split() if t.strip()]
    sc = str(subject)[:2] if subject else None
    freq = str(frequency) if frequency is not None else None
    out = []
    for c in _CUBES:
        title_f = _fold(c.get("t", ""))
        if not all(t in title_f for t in tokens):
            continue
        if sc is not None and not any(str(s)[:2] == sc for s in (c.get("s") or [])):
            continue
        if freq is not None and str(c.get("f")) != freq:
            continue
        out.append(_cube_view(c))
        if len(out) >= limit:
            break
    return out


def _cube_view(c: Dict[str, Any]) -> Dict[str, Any]:
    """Expand a compact cube record into a friendly dict."""
    subj = c.get("s") or []
    return {
        "pid": c["p"],
        "title": c.get("t"),
        "subjects": [{"code": str(s), "name": _SUBJECT_TOP.get(str(s)[:2], "")}
                     for s in subj],
        "frequency": _CODESETS.get("frequency", {}).get(str(c.get("f")), c.get("f")),
        "frequency_code": c.get("f"),
        "start": c.get("a"),
        "end": c.get("z"),
        "dataflow": f"DF_{c['p']}",
    }


def get_cube(pid: Union[int, str]) -> Optional[Dict[str, Any]]:
    """Cube-level metadata from the embedded index (title, subjects,
    frequency, coverage). Returns None if the PID is not an active cube in
    the embedded index — use get_cube_metadata(pid) for the live DSD of any
    cube (incl. archived)."""
    pid = int(pid)
    c = _CUBE_INDEX.get(pid)
    return _cube_view(c) if c else None


def describe_cube(pid: Union[int, str]) -> str:
    """One-glance markdown summary of a cube from the embedded index."""
    v = get_cube(pid)
    if not v:
        return f"PID {pid}: not in embedded active index (try get_cube_metadata)."
    subs = ", ".join(f"{s['code']} {s['name']}" for s in v["subjects"])
    return (f"PID {v['pid']}  ({v['dataflow']})\n"
            f"  {v['title']}\n"
            f"  Subjects: {subs}\n"
            f"  Frequency: {v['frequency']}   Coverage: {v['start']} -> {v['end']}")


def list_catalog() -> List[Dict[str, Any]]:
    """The curated Canada macro catalog (headline series, the fast path)."""
    return [dict(alias=k, **v) for k, v in CATALOG.items()]


def search_catalog(keyword: str) -> List[Dict[str, Any]]:
    """Search the curated catalog by alias or label."""
    kf = _fold(keyword)
    return [dict(alias=k, **v) for k, v in CATALOG.items()
            if kf in _fold(k) or kf in _fold(v.get("label", ""))]


# --------------------------------------------------------------------------
# Code-set lookups
# --------------------------------------------------------------------------

def get_frequency(code: Union[int, str]) -> Optional[str]:
    return _CODESETS.get("frequency", {}).get(str(code))


def get_uom(code: Union[int, str]) -> Optional[str]:
    return _CODESETS.get("uom", {}).get(str(code))


def get_scalar_factor(code: Union[int, str]) -> Optional[str]:
    return _CODESETS.get("scalar", {}).get(str(code))


def list_frequencies() -> Dict[str, str]:
    return dict(_CODESETS.get("frequency", {}))


# --------------------------------------------------------------------------
# On-demand cube structure (live DSD — progressive disclosure L3)
# --------------------------------------------------------------------------

_CUBE_META_CACHE: Dict[int, Dict[str, Any]] = {}


def get_cube_metadata(pid: Union[int, str], refresh: bool = False) -> Dict[str, Any]:
    """Fetch the live DSD for a cube: its dimensions and members.

    Reaches ANY cube (active or archived), not just those in the embedded
    index. Cached per-pid for the session.

    Returns::

        {
          "pid": 18100004,
          "title": "Consumer Price Index, monthly, not seasonally adjusted",
          "frequency": "Monthly", "frequency_code": 6,
          "nb_series": 2139, "start": "1914-...", "end": "...",
          "dimensions": [
            {"position": 1, "name": "Geography",
             "members": [{"id": "2", "name": "Canada", "parent": None}, ...]},
            ...
          ],
        }
    """
    pid = int(pid)
    if not refresh and pid in _CUBE_META_CACHE:
        return _CUBE_META_CACHE[pid]
    payload = _wds_post("getCubeMetadata", [{"productId": pid}])
    if not payload or payload[0].get("status") != "SUCCESS":
        raise StatCanError(f"getCubeMetadata({pid}) returned no SUCCESS object")
    o = payload[0]["object"]
    dims = []
    for dm in o.get("dimension", []):
        members = [{"id": str(m.get("memberId")),
                    "name": m.get("memberNameEn"),
                    "parent": (str(m.get("parentMemberId"))
                               if m.get("parentMemberId") is not None else None)}
                   for m in dm.get("member", [])]
        dims.append({"position": dm.get("dimensionPositionId"),
                     "name": dm.get("dimensionNameEn"),
                     "members": members})
    meta = {
        "pid": pid,
        "title": o.get("cubeTitleEn"),
        "frequency": get_frequency(o.get("frequencyCode")),
        "frequency_code": o.get("frequencyCode"),
        "nb_series": o.get("nbSeriesCube"),
        "start": o.get("cubeStartDate"),
        "end": o.get("cubeEndDate"),
        "archived": o.get("archiveStatusEn"),
        "dimensions": dims,
    }
    _CUBE_META_CACHE[pid] = meta
    return meta


def get_dimensions(pid: Union[int, str]) -> List[Dict[str, Any]]:
    """Ordered dimension list for a cube (sugar over get_cube_metadata)."""
    return get_cube_metadata(pid)["dimensions"]


def get_dimension_members(pid: Union[int, str],
                          dimension: Union[int, str]) -> List[Dict[str, Any]]:
    """Members of one dimension, addressed by position (int) or name (str,
    accent/case-insensitive)."""
    meta = get_cube_metadata(pid)
    for d in meta["dimensions"]:
        if (isinstance(dimension, int) and d["position"] == dimension) or \
           (isinstance(dimension, str) and _fold(d["name"]) == _fold(dimension)):
            return d["members"]
    valid = [(d["position"], d["name"]) for d in meta["dimensions"]]
    raise StatCanError(f"dimension {dimension!r} not in cube {pid}; valid: {valid}")


# --------------------------------------------------------------------------
# Data layer (live SDMX)
# --------------------------------------------------------------------------

def _normalize_vectors(vectors: Union[str, int, Sequence[Union[str, int]]]
                       ) -> List[str]:
    if isinstance(vectors, (str, int)):
        vectors = [vectors]
    out = []
    for v in vectors:
        # Catalog aliases ("cpi", "unemployment_rate", ...) resolve to their
        # fixed vector so PRISM can pass them anywhere a vector is accepted.
        if isinstance(v, str) and v in CATALOG:
            cv = CATALOG[v].get("vector")
            if not cv:
                raise StatCanError(
                    f"catalog alias {v!r} has no fixed vector; use "
                    f"query({CATALOG[v]['pid']}, ...) to pick the slice")
            v = cv
        out.append(str(v).lower().lstrip("v"))
    return out


# Data is retrieved through WDS (clean refPer/value/vectorId per point);
# SDMX-JSON is buggy for multi-series and is only the documented raw
# escape hatch (get_data_sdmx). For a full-history / arbitrary-range pull
# WDS returns the latest N periods, so we fetch a generous window and
# filter client-side on the reliable ISO refPer.
_DEFAULT_HISTORY_N = 50000
_MAX_COORDS = 300
_WDS_BATCH = 250


def _refper_date(refper: Optional[str]):
    import datetime
    ymd = _parse_start(refper)
    return datetime.date(*ymd) if ymd else None


def _bound_date(period: Optional[str], end: bool):
    """Convert a start/end bound (YYYY, YYYY-MM, YYYY-Qn, YYYY-MM-DD) to a
    date. ``end=True`` snaps to the last day of the period."""
    import calendar
    import datetime
    if not period:
        return None
    p = str(period)
    qm = re.fullmatch(r"(\d{4})-?Q([1-4])", p, re.IGNORECASE)
    if qm:
        y, q = int(qm.group(1)), int(qm.group(2))
        m = q * 3 if end else q * 3 - 2
        d = calendar.monthrange(y, m)[1] if end else 1
        return datetime.date(y, m, d)
    parts = p.split("-")
    y = int(parts[0])
    if len(parts) == 1:
        return datetime.date(y, 12, 31) if end else datetime.date(y, 1, 1)
    m = int(parts[1])
    if len(parts) == 2:
        d = calendar.monthrange(y, m)[1] if end else 1
        return datetime.date(y, m, d)
    return datetime.date(y, m, int(parts[2]))


def _parse_wds_object(obj: Dict[str, Any], start_d=None, end_d=None
                      ) -> Dict[str, Any]:
    """Parse one WDS getData* object into a clean series dict."""
    dps = obj.get("vectorDataPoint", []) or []
    fc = dps[-1].get("frequencyCode") if dps else None
    scalar = get_scalar_factor(dps[-1].get("scalarFactorCode")) if dps else None
    obs: Dict[str, Any] = {}
    for dp in dps:
        d = _refper_date(dp.get("refPer"))
        if d and start_d and d < start_d:
            continue
        if d and end_d and d > end_d:
            continue
        period = _period_from_refper(dp.get("refPer"), dp.get("frequencyCode"))
        obs[period] = _coerce_number(dp.get("value"))
    vid = obj.get("vectorId")
    return {
        "vector": str(vid) if vid is not None else None,
        "pid": obj.get("productId"),
        "coordinate": obj.get("coordinate"),
        "dimensions": {},
        "title": None,
        "frequency": get_frequency(fc),
        "frequency_code": fc,
        "scalar_factor": scalar,
        "observations": obs,
    }


def _period_from_refper(refper: Optional[str], freq_code: Any) -> str:
    ymd = _parse_start(refper)
    if not ymd:
        return str(refper)
    return _format_period(ymd, _FREQ_TO_GRAN.get(str(freq_code), "D"))


def get_vector(vectors: Union[str, int, Sequence[Union[str, int]]],
               latest_n: Optional[int] = None,
               start: Optional[str] = None,
               end: Optional[str] = None,
               enrich: bool = True) -> List[Dict[str, Any]]:
    """Fetch one or more series by vector id (the recommended way to pin a
    specific series; vectors never change).

    Accepts "v41690973", "41690973", or 41690973, and a list for multi-series
    pulls. Uses WDS getDataFromVectorsAndLatestNPeriods (clean, reliable).

    Args:
        latest_n: return only the most recent N observations per series.
        start / end: period bounds (YYYY, YYYY-MM, YYYY-Qn, or YYYY-MM-DD);
            applied client-side on the reliable refPer date.
        enrich: attach the series title/frequency from getSeriesInfoFromVector.
    """
    vlist = _normalize_vectors(vectors)
    n = latest_n or _DEFAULT_HISTORY_N
    body = [{"vectorId": int(v), "latestN": n} for v in vlist]
    payload = _wds_post("getDataFromVectorsAndLatestNPeriods", body)
    sb = _bound_date(start, False)
    eb = _bound_date(end, True)
    out = [_parse_wds_object(item["object"], sb, eb)
           for item in payload if item.get("status") == "SUCCESS"]
    if enrich and out:
        info = {i["vector"]: i for i in get_series_info(vlist)}
        for s in out:
            si = info.get(s["vector"])
            if si:
                s["title"] = si["title"]
    return out


_SERIES_INFO_CACHE: Dict[str, Dict[str, Any]] = {}


def get_series_info(vectors: Union[str, int, Sequence[Union[str, int]]]
                    ) -> List[Dict[str, Any]]:
    """Series-level metadata for one or more vectors (title, frequency,
    scalar factor, decimals, product id, coordinate). Cached per vector.

    Returns ``[{vector, title, frequency, frequency_code, scalar_factor,
    decimals, pid, coordinate}, ...]``.
    """
    vlist = _normalize_vectors(vectors)
    missing = [v for v in vlist if v not in _SERIES_INFO_CACHE]
    if missing:
        payload = _wds_post("getSeriesInfoFromVector",
                            [{"vectorId": int(v)} for v in missing])
        for item in payload:
            if item.get("status") != "SUCCESS":
                continue
            o = item["object"]
            vid = str(o.get("vectorId"))
            _SERIES_INFO_CACHE[vid] = {
                "vector": vid,
                "title": o.get("SeriesTitleEn"),
                "frequency": get_frequency(o.get("frequencyCode")),
                "frequency_code": o.get("frequencyCode"),
                "scalar_factor": get_scalar_factor(o.get("scalarFactorCode")),
                "decimals": o.get("decimals"),
                "pid": o.get("productId"),
                "coordinate": o.get("coordinate"),
            }
    return [_SERIES_INFO_CACHE[v] for v in vlist if v in _SERIES_INFO_CACHE]


def _vector_freq(vector: str) -> Optional[int]:
    """Frequency code for a vector (cached via get_series_info)."""
    info = get_series_info(vector)
    return info[0]["frequency_code"] if info else None


def query(pid: Union[int, str], latest_n: Optional[int] = None,
          start: Optional[str] = None, end: Optional[str] = None,
          coordinate: Optional[str] = None,
          **dim_filters: Any) -> List[Dict[str, Any]]:
    """Fetch series from a cube by dimension filters (the universe-first
    data entry point).

    Resolves dimension filters to explicit coordinates against the live cube
    metadata, then pulls clean data via WDS getDataFromCubePidCoord. A
    dimension not supplied is wildcarded to all its members (OR). Returned
    series carry resolved ``dimensions`` (name -> member name) so PRISM can
    identify each one without parsing keys.

    Args:
        latest_n: most recent N observations per series.
        start / end: period bounds (applied on the reliable refPer date).
        coordinate: pass an explicit 10-position coordinate to bypass
            dimension resolution.
        **dim_filters: address a dimension by name (accent/case/partial-
            insensitive) or position (``pos1=``). Values may be a member id,
            member name, list, or ``+``-joined string; multiple values OR.

    Examples::

        statcan_client.query(18100004, Geography="Canada",
                             Products="All-items", start="2024-01")
        # all provinces, all-items CPI, last 12 months:
        statcan_client.query(18100004, Products="All-items", latest_n=12)
    """
    pid = int(pid)
    if coordinate:
        specs = [{"coordinate": coordinate, "dimensions": {}}]
    else:
        specs = build_coordinate(pid, **dim_filters)
    title = (get_cube(pid) or {}).get("title") or \
            get_cube_metadata(pid).get("title")

    n = latest_n or _DEFAULT_HISTORY_N
    sb = _bound_date(start, False)
    eb = _bound_date(end, True)
    by_coord = {s["coordinate"]: s["dimensions"] for s in specs}

    out: List[Dict[str, Any]] = []
    coords = [s["coordinate"] for s in specs]
    for i in range(0, len(coords), _WDS_BATCH):
        chunk = coords[i:i + _WDS_BATCH]
        body = [{"productId": pid, "coordinate": c, "latestN": n}
                for c in chunk]
        payload = _wds_post("getDataFromCubePidCoordAndLatestNPeriods", body)
        for item in payload:
            if item.get("status") != "SUCCESS":
                continue
            s = _parse_wds_object(item["object"], sb, eb)
            s["dimensions"] = by_coord.get(s["coordinate"], {})
            s["title"] = title
            out.append(s)
    return out


def get_data(pid: Union[int, str], coordinate: str,
             latest_n: Optional[int] = None,
             start: Optional[str] = None, end: Optional[str] = None
             ) -> Optional[Dict[str, Any]]:
    """Fetch one series by explicit (pid, coordinate) via WDS. The coordinate
    is the 10-position dot string (e.g. "2.2.0.0.0.0.0.0.0.0")."""
    res = query(pid, latest_n=latest_n, start=start, end=end,
                coordinate=coordinate)
    return res[0] if res else None


def build_coordinate(pid: Union[int, str], **dim_filters: Any
                     ) -> List[Dict[str, Any]]:
    """Resolve dimension filters to explicit 10-position coordinates.

    Each kwarg addresses a dimension by name (accent/case/partial-
    insensitive) or position (``pos1=``); values are member ids/names/lists.
    Unspecified dimensions are wildcarded to all members. Returns
    ``[{"coordinate": "2.2.0...", "dimensions": {dim_name: member_name}}]``.
    Raises StatCanError if the cartesian product exceeds the safety cap
    (narrow the query, or use get_full_table_url for whole-cube extraction).
    """
    import itertools
    pid = int(pid)
    meta = get_cube_metadata(pid)
    dims = sorted(meta["dimensions"], key=lambda d: d["position"])
    by_name = {_fold(d["name"]): d for d in dims}
    by_pos = {d["position"]: d for d in dims}

    chosen: Dict[int, List[Dict[str, str]]] = {}
    for raw_key, raw_val in dim_filters.items():
        d = None
        m = re.fullmatch(r"pos(\d+)", raw_key, re.IGNORECASE)
        if m:
            d = by_pos.get(int(m.group(1)))
        if d is None:
            d = by_name.get(_fold(raw_key))
        if d is None:
            kf = _fold(raw_key)
            subs = [dd for nf, dd in by_name.items() if kf in nf or nf in kf]
            if len(subs) == 1:
                d = subs[0]
        if d is None:
            valid = [f"{x['position']}:{x['name']}" for x in dims]
            raise StatCanError(
                f"unknown dimension {raw_key!r} for cube {pid}; valid: {valid}")
        ids = _resolve_members(d, raw_val, pid)
        members_by_id = {str(mm["id"]): mm for mm in d["members"]}
        chosen[d["position"]] = [{"id": i, "name": members_by_id[i]["name"]}
                                 for i in ids]

    # Per-dimension option lists (chosen, or all members = wildcard).
    per_dim: List[List[Dict[str, str]]] = []
    total = 1
    for d in dims:
        opts = chosen.get(d["position"]) or [
            {"id": str(mm["id"]), "name": mm["name"]} for mm in d["members"]]
        per_dim.append(opts)
        total *= len(opts)
    if total > _MAX_COORDS:
        raise StatCanError(
            f"query resolves to {total} series (cap {_MAX_COORDS}). Narrow "
            f"the dimension filters, or use get_full_table_url({pid}) for "
            f"whole-cube extraction.")

    out = []
    for combo in itertools.product(*per_dim):
        ids = [c["id"] for c in combo]
        coord = ".".join(ids + ["0"] * (10 - len(ids)))
        dim_names = {dims[i]["name"]: combo[i]["name"] for i in range(len(dims))}
        out.append({"coordinate": coord, "dimensions": dim_names})
    return out


def get_data_sdmx(dataflow: Union[int, str], key: str = "",
                  start: Optional[str] = None, end: Optional[str] = None,
                  latest_n: Optional[int] = None,
                  first_n: Optional[int] = None) -> List[Dict[str, Any]]:
    """Raw StatCan SDMX REST data interface (the standards path from the
    SDMX user guide). ``dataflow`` is a pid (int -> DF_<pid>) or a flowRef
    string ("DF_18100004"); ``key`` is the dot-separated SDMX key (wildcard
    by omission, OR with ``+``).

    Note: StatCan SDMX-JSON keys observations by a global index and mislabels
    TIME_PERIOD; the wrapper corrects periods, but for reliable per-series
    identity prefer query()/get_vector() (WDS-backed). Kept for SDMX
    standards compatibility.
    """
    if isinstance(dataflow, int) or str(dataflow).isdigit():
        pid = int(dataflow)
        flow = f"DF_{pid}"
    else:
        flow = str(dataflow)
        m = re.search(r"(\d+)", flow)
        pid = int(m.group(1)) if m else None
    params = _period_params(start, end, latest_n, first_n)
    cube = _CUBE_INDEX.get(pid) if pid else None
    freq_hint = cube.get("f") if cube else None
    return _parse_sdmx_json(_sdmx_get(f"data/{flow}/{key}", params),
                            freq_hint=freq_hint)


def get_full_table_url(pid: Union[int, str], fmt: str = "csv",
                       lang: str = "en") -> Optional[str]:
    """Return the download URL for a whole cube as a zipped CSV or SDMX-ML
    file (the documented bulk-extraction path). fmt is "csv" or "sdmx"."""
    pid = int(pid)
    if fmt.lower() == "sdmx":
        r = _wds_get(f"getFullTableDownloadSDMX/{pid}")
    else:
        r = _wds_get(f"getFullTableDownloadCSV/{pid}/{lang}")
    return r.get("object") if r.get("status") == "SUCCESS" else None


def _resolve_members(dim: Dict[str, Any], value: Any, pid: int) -> List[str]:
    """Resolve a kwarg value (id / name / list / '+'-joined) to member ids,
    validating against the dimension's members."""
    if isinstance(value, (list, tuple)):
        raw_vals = list(value)
    else:
        raw_vals = str(value).split("+")
    members = dim["members"]
    by_id = {str(m["id"]): m["id"] for m in members}
    by_name = {_fold(m["name"]): m["id"] for m in members}
    out = []
    for rv in raw_vals:
        rv_s = str(rv).strip()
        if rv_s in by_id:
            out.append(by_id[rv_s])
        elif _fold(rv_s) in by_name:
            out.append(str(by_name[_fold(rv_s)]))
        else:
            sample = [f"{m['id']}:{m['name']}" for m in members[:8]]
            raise StatCanError(
                f"member {rv_s!r} not valid for dimension "
                f"{dim['name']!r} (pos {dim['position']}) of cube {pid}; "
                f"e.g. {sample} ... use get_dimension_members({pid}, "
                f"{dim['position']}) for the full list")
    return out


def _period_params(start, end, latest_n, first_n) -> Dict[str, Any]:
    params: Dict[str, Any] = {}
    if start:
        params["startPeriod"] = start
    if end:
        params["endPeriod"] = end
    if latest_n:
        params["lastNObservations"] = latest_n
    if first_n:
        params["firstNObservations"] = first_n
    return params


def latest(vector_or_alias: Union[str, int]) -> Optional[Dict[str, Any]]:
    """Most-recent observation for a vector id or a catalog alias.

    Returns ``{value, period, vector, title, frequency}`` or None.
    """
    if isinstance(vector_or_alias, str) and vector_or_alias in CATALOG:
        vec = CATALOG[vector_or_alias].get("vector")
        if not vec:
            raise StatCanError(
                f"catalog alias {vector_or_alias!r} has no fixed vector; "
                f"use query({CATALOG[vector_or_alias]['pid']}, ...)")
        vector_or_alias = vec
    series = get_vector(vector_or_alias, latest_n=1)
    if not series or not series[0]["observations"]:
        return None
    s = series[0]
    period, value = next(iter(s["observations"].items()))
    return {"value": value, "period": period, "vector": s["vector"],
            "title": s.get("title"), "frequency": s.get("frequency")}


# --------------------------------------------------------------------------
# PRISM ergonomics — pandas conversion
# --------------------------------------------------------------------------

def series_to_dataframe(series: List[Dict[str, Any]],
                        value_col: str = "value", wide: bool = False):
    """Convert parsed series to a tidy (long) or wide pandas DataFrame.

    Long: one row per (series, period) with each dimension id as a column,
    plus ``period`` and ``value_col``. Wide: one column per series (labelled
    by VECTOR_ID when available), period as the index.
    """
    try:
        import pandas as pd
    except ImportError as e:  # pragma: no cover
        raise ImportError("series_to_dataframe requires pandas") from e

    if wide:
        cols = {}
        for s in series:
            label = s.get("vector") or s.get("coordinate") or "series"
            cols[f"v{label}" if str(label).isdigit() else str(label)] = \
                pd.Series(s["observations"])
        return pd.DataFrame(cols).sort_index()

    rows = []
    for s in series:
        base = dict(s.get("dimensions") or {})
        base["vector"] = s.get("vector")
        for period, val in s["observations"].items():
            rows.append({**base, "period": period, value_col: val})
    return pd.DataFrame(rows)


def fetch_aligned(specs: List[Dict[str, Any]],
                  start: Optional[str] = None, end: Optional[str] = None):
    """Fetch multiple series (by vector) and merge into a wide DataFrame
    indexed by period. Each spec is ``{"name": str, "vector": str|int}``.
    Mixed frequencies sit alongside each other with NaN where unaligned.
    """
    try:
        import pandas as pd
    except ImportError as e:  # pragma: no cover
        raise ImportError("fetch_aligned requires pandas") from e

    cols = {}
    for spec in specs:
        series = get_vector(spec["vector"], start=start, end=end)
        obs = series[0]["observations"] if series else {}
        cols[spec["name"]] = pd.Series(obs)
    return pd.DataFrame(cols).sort_index()


# --------------------------------------------------------------------------
# Refresh (offline tool — never called from the PRISM sandbox)
# --------------------------------------------------------------------------

def refresh_ontology(*, write_to: Optional[str] = None,
                     active_only: bool = True,
                     verbose: bool = True) -> Dict[str, Any]:
    """Re-harvest the embedded ontology from live StatCan WDS.

    Pulls getCodeSets + getAllCubesListLite, compacts them, and (if
    ``write_to`` is a path to this module) rewrites the
    ``_STATCAN_ONTOLOGY_JSON`` literal in place.

    Args:
        write_to: path to statcan_client.py to rewrite (typically __file__).
        active_only: keep only active cubes (archiveStatus "2").
        verbose: print progress.
    """
    if verbose:
        print("Fetching getCodeSets ...")
    cs = _wds_get("getCodeSets")["object"]

    def _clean(s):
        # Strip control characters so the embedded JSON literal stays valid.
        return re.sub(r"[\x00-\x1f\x7f]", " ", s or "").strip()

    def _ck(items, kcode, kdesc):
        return {str(it[kcode]): _clean(it[kdesc]) for it in items
                if it.get(kdesc) is not None}

    subjects = {str(s["subjectCode"]): _clean(s["subjectEn"]) for s in cs["subject"]}
    subject_top = {k: v for k, v in subjects.items() if len(k) == 2}
    codesets = {
        "frequency": _ck(cs["frequency"], "frequencyCode", "frequencyDescEn"),
        "scalar": _ck(cs["scalar"], "scalarFactorCode", "scalarFactorDescEn"),
        "symbol": _ck(cs["symbol"], "symbolCode", "symbolDescEn"),
        "status": _ck(cs["status"], "statusCode", "statusDescEn"),
        "uom": _ck(cs["uom"], "memberUomCode", "memberUomEn"),
        "classificationType": _ck(cs["classificationType"],
                                  "classificationTypeCode",
                                  "classificationTypeEn"),
    }

    if verbose:
        print("Fetching getAllCubesListLite ...")
    cubes_raw = _wds_get("getAllCubesListLite")
    cubes = []
    for c in cubes_raw:
        if active_only and c.get("archived") != ARCHIVE_ACTIVE:
            continue
        cubes.append({
            "p": c["productId"],
            "t": _clean(c.get("cubeTitleEn")),
            "s": [str(x) for x in (c.get("subjectCode") or [])],
            "f": c.get("frequencyCode"),
            "a": (c.get("cubeStartDate") or "")[:7],
            "z": (c.get("cubeEndDate") or "")[:7],
        })

    import datetime
    ontology = {
        "generated": datetime.datetime.utcnow().strftime("%Y-%m-%d"),
        "subjects": subjects,
        "subject_top": subject_top,
        "codesets": codesets,
        "cubes": cubes,
    }
    if verbose:
        print(f"  subjects: {len(subjects)} ({len(subject_top)} top-level)")
        print(f"  cubes: {len(cubes)} ({'active only' if active_only else 'all'})")
        for k, v in codesets.items():
            print(f"  codeset {k}: {len(v)}")

    if write_to:
        compact = json.dumps(ontology, separators=(",", ":"), ensure_ascii=False)
        with open(write_to, "r", encoding="utf-8") as f:
            text = f.read()
        pattern = r'_STATCAN_ONTOLOGY_JSON\s*=\s*r"""(.*?)"""'
        if not re.search(pattern, text, re.DOTALL):
            raise StatCanError(
                f"Could not locate _STATCAN_ONTOLOGY_JSON block in {write_to}")
        new_block = f'_STATCAN_ONTOLOGY_JSON = r"""\n{compact}\n"""'
        text = re.sub(pattern, new_block, text, count=1, flags=re.DOTALL)
        with open(write_to, "w", encoding="utf-8") as f:
            f.write(text)
        if verbose:
            print(f"Wrote refreshed ontology to {write_to} "
                  f"({len(compact):,} chars)")
    return ontology


